static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;
static constexpr uint32_t ALIGN_ELEMS = 2048;

static inline uint32_t AlignDown(uint32_t x, uint32_t a) { return (x / a) * a; }
static inline uint32_t CeilDiv(uint32_t a, uint32_t b) { return (a + b - 1) / b; }

static ge::graphStatus TilingFunc(gert::TilingContext *context) {
    Ca6k04617CustomTilingData tiling;

    const gert::StorageShape* x_storage = context->GetInputShape(0);
    const gert::Shape* x_shape = x_storage->GetOriginShape();
    const uint32_t n = static_cast<uint32_t>(x_shape->GetDim(0));
    const uint32_t cIn = static_cast<uint32_t>(x_shape->GetDim(1));
    const uint32_t hIn = static_cast<uint32_t>(x_shape->GetDim(2));
    const uint32_t wIn = static_cast<uint32_t>(x_shape->GetDim(3));

    const gert::StorageShape* w_storage = context->GetInputShape(1);
    const gert::Shape* w_shape = w_storage->GetOriginShape();
    uint32_t cOut = static_cast<uint32_t>(w_shape->GetDim(0));

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    uint32_t kernelSize = static_cast<uint32_t>(attrs->GetAttrNum(0));
    uint32_t stride = static_cast<uint32_t>(attrs->GetAttrNum(1));
    uint32_t padding = static_cast<uint32_t>(attrs->GetAttrNum(2));
    uint32_t poolKernelSize = static_cast<uint32_t>(attrs->GetAttrNum(3));
    uint32_t poolStride = static_cast<uint32_t>(attrs->GetAttrNum(4));

    uint32_t hOut = (hIn + 2 * padding - kernelSize) / stride + 1;
    uint32_t wOut = (wIn + 2 * padding - kernelSize) / stride + 1;
    uint32_t hOutPool = (hOut - poolKernelSize) / poolStride + 1;
    uint32_t wOutPool = (wOut - poolKernelSize) / poolStride + 1;

    uint32_t totalLen = n * cOut * hOutPool * wOutPool;
    uint32_t maxTile = UB_BUDGET_BYTES / sizeof(float) / 6;
    maxTile = AlignDown(maxTile, ALIGN_ELEMS);
    if (maxTile < ALIGN_ELEMS) maxTile = ALIGN_ELEMS;
    uint32_t tileLen = (totalLen < maxTile) ? totalLen : maxTile;

    uint32_t numTiles = CeilDiv(totalLen, tileLen);
    uint32_t blockDim = numTiles;
    if (blockDim < 8) blockDim = 8;
    if (blockDim > 24) blockDim = 24;
    context->SetBlockDim(blockDim);

    tiling.set_totalLength(totalLen);
    tiling.set_tileLength(tileLen);
    tiling.set_blockDim(blockDim);
    tiling.set_n(n);
    tiling.set_cIn(cIn);
    tiling.set_hIn(hIn);
    tiling.set_wIn(wIn);
    tiling.set_cOut(cOut);
    tiling.set_hOut(hOut);
    tiling.set_wOut(wOut);
    tiling.set_kernelSize(kernelSize);
    tiling.set_stride(stride);
    tiling.set_padding(padding);
    tiling.set_poolKernelSize(poolKernelSize);
    tiling.set_poolStride(poolStride);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}
